const q = $('Code: Questions').item.json;
const r = $input.item.json;
const body = r.body || r;
const headers = r.headers || {};
return {
  json: {
    questionId: q.questionId,
    question: q.question,
    topic: q.topic,
    modelLabel: 'xAI Grok 3',
    modelSlug: 'x-ai/grok-3:exacto',
    providerPinned: 'xAI only',
    providerActual: headers['x-openrouter-provider'] || headers['X-Openrouter-Provider'] || 'see-model-field',
    modelActual: body.model || 'unknown',
    response: body.choices?.[0]?.message?.content || 'ERROR: ' + JSON.stringify(body).substring(0, 300),
    promptTokens: body.usage?.prompt_tokens || 0,
    completionTokens: body.usage?.completion_tokens || 0
  }
};

const items = $input.all();

const byModel = {};
for (const item of items) {
  const d = item.json;
  const key = d.modelLabel;
  if (!byModel[key]) {
    byModel[key] = {
      modelLabel: d.modelLabel,
      modelSlug: d.modelSlug,
      providerPinned: d.providerPinned,
      providerActual: d.providerActual,
      modelActual: d.modelActual,
      answers: []
    };
  }
  byModel[key].answers.push({
    questionId: d.questionId,
    topic: d.topic,
    question: d.question,
    response: d.response,
    totalTokens: (d.promptTokens || 0) + (d.completionTokens || 0)
  });
}

for (const key of Object.keys(byModel)) {
  byModel[key].answers.sort((a, b) => a.questionId - b.questionId);
}

return [{
  json: {
    runAt: new Date().toISOString(),
    totalResponses: items.length,
    modelsRan: Object.keys(byModel).length,
    results: Object.values(byModel)
  }
}];
